script:
frappe.ui.form.on('Employee', {
	refresh(frm) {
		if (frm.is_new()) return;
		frm.add_custom_button(__('Generate Letter'), () => {
			frappe.new_doc('HR Letter', {
				recipient_type: 'Employee',
				recipient: frm.doc.name,
			});
		}, __('HR Letters'));
		frm.add_custom_button(__('View Letters'), () => {
			frappe.set_route('List', 'HR Letter', { recipient: frm.doc.name });
		}, __('HR Letters'));
	},
});

frappe.ui.form.on('Job Applicant', {
	refresh(frm) {
		if (frm.is_new()) return;
		frm.add_custom_button(__('Generate Letter'), () => {
			frappe.new_doc('HR Letter', {
				recipient_type: 'Job Applicant',
				recipient: frm.doc.name,
			});
		}, __('HR Letters'));
		frm.add_custom_button(__('View Letters'), () => {
			frappe.set_route('List', 'HR Letter', { recipient: frm.doc.name });
		}, __('HR Letters'));
	},
});
